import java.util.PriorityQueue

fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    val rows = m.toInt()
    val cols = n.toInt()
    val dist = Array(rows) { Array(cols) { Array(2) { Long.MAX_VALUE } } }
    dist[0][0][1] = 1 // initial state: (0,0) at parity 1 (odd time)
    val pq = PriorityQueue<MutableList<Long>>(compareBy { it[0] })
    pq.add(arrayOf(1L, 0L, 0L, 1L).toMutableList())

    while (pq.isNotEmpty()) {
        val current = pq.poll()
        val cost = current[0]
        val i = current[1].toInt()
        val j = current[2].toInt()
        val parity = current[3].toInt()

        // Check if we reached the destination
        if (i == rows - 1 && j == cols - 1) {
            return cost
        }

        // Check if current cost is higher than the recorded one
        if (cost > dist[i][j][parity]) {
            continue
        }

        // Process transitions
        if (parity == 1) { // odd time: can move right or down
            // Move right
            if (j + 1 < cols) {
                val newI = i
                val newJ = j + 1
                val newCost = cost + (newI + 1) * (newJ + 1)
                if (newCost < dist[newI][newJ][0]) {
                    dist[newI][newJ][0] = newCost
                    pq.add(arrayOf(newCost, newI.toLong(), newJ.toLong(), 0L).toMutableList())
                }
            }
            // Move down
            if (i + 1 < rows) {
                val newI = i + 1
                val newJ = j
                val newCost = cost + (newI + 1) * (newJ + 1)
                if (newCost < dist[newI][newJ][0]) {
                    dist[newI][newJ][0] = newCost
                    pq.add(arrayOf(newCost, newI.toLong(), newJ.toLong(), 0L).toMutableList())
                }
            }
        } else { // even time: wait
            val newCost = cost + waitCost[i][j]
            if (newCost < dist[i][j][1]) {
                dist[i][j][1] = newCost
                pq.add(arrayOf(newCost, i.toLong(), j.toLong(), 1L).toMutableList())
            }
        }
    }
    // If not found (should not happen)
    return -1
}
